1	/**
2	 * LayerInfinite MCP Server — decision-tracker.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Decision ID generation + episode tracking + buffer flush.
5	 * Replaces episode-tracker.ts (V1 redirect-loop prevention).
6	 *
7	 * Decision ID format: dec_{ts12}_{agent4}_{rand4}
8	 *   ts12    — base62-encoded timestamp (lexicographically sortable)
9	 *   agent4  — base62-encoded djb2 hash of agentId
10	 *   rand4   — 4 random base62 chars (collision prob < 10^-9 per ms)
11	 *
12	 * Buffer flushes every 5s to LI API. Disk queue fallback at
13	 * .li-queue/decisions.jsonl when API is unreachable.
14	 * ══════════════════════════════════════════════════════════════
15	 */
16	
17	import { appendFileSync, mkdirSync, existsSync } from 'node:fs';
18	import { join } from 'node:path';
19	import { randomBytes } from 'node:crypto';
20	import type { DecisionRecord, Episode } from './types.js';
21	import type { LiApiClient } from './rest-client.js';
22	import { logger } from './logger.js';
23	
24	const log = logger.forTool('decision-tracker');
25	
26	// ── Decision ID generation ──────────────────────────────────
27	
28	const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
29	const FLUSH_INTERVAL_MS = 5_000;
30	const EPISODE_TTL_MS = 30 * 60 * 1000;
31	const MAX_COACHING_PER_EPISODE = 3;
32	const DISK_QUEUE_DIR = '.li-queue';
33	const DISK_QUEUE_FILE = 'decisions.jsonl';
34	
35	function base62Encode(n: number, minLen: number): string {
36	  let s = '';
37	  let v = n;
38	  while (v > 0) {
39	    s = BASE62[v % 62] + s;
40	    v = Math.floor(v / 62);
41	  }
42	  return s.padStart(minLen, '0');
43	}
44	
45	function djb2(s: string): number {
46	  let hash = 5381;
47	  for (let i = 0; i < s.length; i++) {
48	    hash = ((hash << 5) + hash) + s.charCodeAt(i);
49	    hash = hash >>> 0;
50	  }
51	  return hash;
52	}
53	
54	function randomBase62(len: number): string {
55	  let s = '';
56	  const bytes = randomBytes(len);
57	  for (let i = 0; i < len; i++) {
58	    s += BASE62[bytes[i] % 62];
59	  }
60	  return s;
61	}
62	
63	export function generateDecisionId(agentId: string): string {
64	  const ts12 = base62Encode(Date.now(), 12);
65	  const agent4 = base62Encode(djb2(agentId), 4).slice(0, 4);
66	  const rand4 = randomBase62(4);
67	  return `dec_${ts12}_${agent4}_${rand4}`;
68	}
69	
70	function generateEpisodeId(): string {
71	  const ts10 = base62Encode(Date.now(), 10);
72	  const rand6 = randomBase62(6);
73	  return `ep_${ts10}_${rand6}`;
74	}
75	
76	// ══════════════════════════════════════════════════════════════
77	// DecisionTracker
78	// ══════════════════════════════════════════════════════════════
79	
80	export class DecisionTracker {
81	  private readonly episodes = new Map<string, Episode>();
82	  private readonly buffer: DecisionRecord[] = [];
83	  private flushTimer: ReturnType<typeof setInterval> | null = null;
84	  private flushing = false;
85	  private queueDirEnsured = false;
86	
87	  constructor(private readonly liApi: LiApiClient) {}
88	
89	  // ── Episode management ───────────────────────────────────
90	
91	  startEpisode(agentId: string, customerId: string): Episode {
92	    this.cleanExpiredEpisodes();
93	
94	    const episode: Episode = {
95	      episodeId: generateEpisodeId(),
96	      agentId,
97	      sessionStart: new Date().toISOString(),
98	      decisions: [],
99	      coachingCount: 0,
100	    };
101	
102	    this.episodes.set(episode.episodeId, episode);
103	    log.debug('Episode started', { episodeId: episode.episodeId, agentId, customerId });
104	    return episode;
105	  }
106	
107	  getEpisode(episodeId: string): Episode | undefined {
108	    this.cleanExpiredEpisodes();
109	    return this.episodes.get(episodeId);
110	  }
111	
112	  /** Record a coaching injection. Returns false if cap (3) already reached. */
113	  recordCoaching(episodeId: string): boolean {
114	    const episode = this.episodes.get(episodeId);
115	    if (!episode) return false;
116	    if (episode.coachingCount >= MAX_COACHING_PER_EPISODE) return false;
117	    episode.coachingCount++;
118	    return true;
119	  }
120	
121	  canCoach(episodeId: string): boolean {
122	    const episode = this.episodes.get(episodeId);
123	    if (!episode) return true; // No episode yet — coaching is allowed
124	    return episode.coachingCount < MAX_COACHING_PER_EPISODE;
125	  }
126	
127	  // ── Decision recording ───────────────────────────────────
128	
129	  recordDecision(record: DecisionRecord): void {
130	    this.buffer.push(record);
131	
132	    // Link to episode
133	    if (this.episodes.size > 0) {
134	      // Find the most recent episode for this agent
135	      let latest: Episode | undefined;
136	      for (const ep of this.episodes.values()) {
137	        if (ep.agentId === record.agentId) {
138	          if (!latest || ep.sessionStart > latest.sessionStart) {
139	            latest = ep;
140	          }
141	        }
142	      }
143	      if (latest) {
144	        latest.decisions.push(record.decisionId);
145	      }
146	    }
147	
148	    // Append to disk queue for durability
149	    this.appendToDiskQueue(record);
150	
151	    log.debug('Decision recorded', { decisionId: record.decisionId });
152	  }
153	
154	  // ── Flush ────────────────────────────────────────────────
155	
156	  async flushBuffer(): Promise<void> {
157	    if (this.buffer.length === 0 || this.flushing) return;
158	
159	    this.flushing = true;
160	    const batch = this.buffer.splice(0);
161	
162	    try {
163	      // Send each decision's outcome to LI API
164	      for (const record of batch) {
165	        const sent = await this.liApi.logOutcome({
166	          agent_id: record.agentId,
167	          customer_id: record.customerId,
168	          issue_type: record.taskType,
169	          action_name: record.actionName,
170	          upstream_name: record.upstreamName,
171	          original_action: record.originalAction,
172	          executed_action: record.executedAction,
173	          mode: record.mode,
174	          rerouted: record.rerouted,
175	          success: true,
176	          response_time_ms: 0,
177	          timestamp: record.timestamp,
178	          ingestion_source: 'mcp',
179	          environment: 'production',
180	        });
181	
182	        if (!sent) {
183	          // Re-queue on failure
184	          this.buffer.push(record);
185	        }
186	      }
187	    } catch (err) {
188	      log.warn('Buffer flush failed — re-queuing', {
189	        count: batch.length,
190	        error: err instanceof Error ? err.message : String(err),
191	      });
192	      this.buffer.push(...batch);
193	    } finally {
194	      this.flushing = false;
195	    }
196	  }
197	
198	  startFlushTimer(): void {
199	    if (this.flushTimer) return;
200	    this.flushTimer = setInterval(() => {
201	      void this.flushBuffer();
202	    }, FLUSH_INTERVAL_MS);
203	  }
204	
205	  stopFlushTimer(): void {
206	    if (this.flushTimer) {
207	      clearInterval(this.flushTimer);
208	      this.flushTimer = null;
209	    }
210	  }
211	
212	  // ── Stats ────────────────────────────────────────────────
213	
214	  get bufferSize(): number {
215	    return this.buffer.length;
216	  }
217	
218	  get episodeCount(): number {
219	    this.cleanExpiredEpisodes();
220	    return this.episodes.size;
221	  }
222	
223	  // ── Private ──────────────────────────────────────────────
224	
225	  private appendToDiskQueue(record: DecisionRecord): void {
226	    try {
227	      if (!this.queueDirEnsured) {
228	        if (!existsSync(DISK_QUEUE_DIR)) {
229	          mkdirSync(DISK_QUEUE_DIR, { recursive: true });
230	        }
231	        this.queueDirEnsured = true;
232	      }
233	      appendFileSync(
234	        join(DISK_QUEUE_DIR, DISK_QUEUE_FILE),
235	        JSON.stringify(record) + '\n',
236	        'utf-8',
237	      );
238	    } catch {
239	      // Disk queue is best-effort — silent failure is acceptable
240	    }
241	  }
242	
243	  private cleanExpiredEpisodes(): void {
244	    const cutoff = Date.now() - EPISODE_TTL_MS;
245	    for (const [id, ep] of this.episodes) {
246	      if (new Date(ep.sessionStart).getTime() < cutoff) {
247	        this.episodes.delete(id);
248	      }
249	    }
250	  }
251	}
252

