117	/**
118	 * Reads and validates environment variables.
119	 * Throws immediately if required vars are missing — fail fast at startup.
120	 */
121	export function loadConfig(): GatewayConfig {
122	  // ── V1 backwards-compatible vars ──────────────────────────
123	  const apiKey = process.env.LAYERINFINITE_API_KEY;
124	  if (!apiKey || apiKey.trim() === '') {
125	    throw new Error(
126	      '[layerinfinite-mcp] LAYERINFINITE_API_KEY is required. ' +
127	      'Get your key from the LayerInfinite dashboard.',
128	    );
129	  }
130	
131	  const baseUrl = (process.env.LAYERINFINITE_BASE_URL ?? 'https://layerinfinite.me').replace(/\/+$/, '');
132	
133	  const rawMode = (process.env.LAYERINFINITE_MODE ?? '').trim().toLowerCase();
134	  let mode: LIMode | null = null;
135	  if (rawMode !== '') {
136	    if (!VALID_MODES.has(rawMode)) {
137	      throw new Error(
138	        `[layerinfinite-mcp] Invalid LAYERINFINITE_MODE="${rawMode}". ` +
139	        `Valid values: recommend, assist, auto. Omit for bootstrap mode.`,
140	      );
141	    }
142	    mode = rawMode as LIMode;
143	  }
144	
145	  const adminKey = process.env.LAYERINFINITE_ADMIN_KEY?.trim() || null;
146	
147	  // ── V2 new vars ──────────────────────────────────────────
148	  const rawUpstream = (process.env.LAYERINFINITE_UPSTREAM_TOOLS ?? '[]').trim();
149	  const upstreamServers = parseUpstreamServers(rawUpstream);
150	
151	  const rawOverrides = (process.env.LAYERINFINITE_MODE_OVERRIDES ?? '{}').trim();
152	  const modeOverrides = parseModeOverrides(rawOverrides);
153	
154	  const shadowMode = (process.env.LAYERINFINITE_SHADOW_MODE ?? 'false').trim().toLowerCase() === 'true';
155	
156	  const rawEnv = (process.env.LAYERINFINITE_ENVIRONMENT ?? 'production').trim().toLowerCase();
157	  if (!VALID_ENVIRONMENTS.has(rawEnv)) {
158	    throw new Error(
159	      `[layerinfinite-mcp] Invalid LAYERINFINITE_ENVIRONMENT="${rawEnv}". ` +
160	      `Valid values: staging, production.`,
161	    );
162	  }
163	  const environment = rawEnv as 'staging' | 'production';
164	
165	  const logLevel = resolveLogLevel();
166	
167	  // ── Classifier config ─────────────────────────────────────
168	  let classifier: ClassifierConfig | null = null;
169	  if ((process.env.LI_CLASSIFIER_ENABLED ?? '').toLowerCase() === 'true') {
170	    classifier = {
171	      enabled: true,
172	      apiKey: process.env.LI_CLASSIFIER_API_KEY ?? process.env.OPENAI_API_KEY ?? null,
173	      model: process.env.LI_CLASSIFIER_MODEL ?? 'gpt-4o-mini',
174	      baseUrl: (process.env.LI_CLASSIFIER_BASE_URL ?? 'https://api.openai.com/v1').replace(/\/+$/, ''),
175	      timeoutMs: Number.parseInt(process.env.LI_CLASSIFIER_TIMEOUT_MS ?? '3000', 10) || 3000,
176	      cacheTtlMs: Number.parseInt(process.env.LI_CLASSIFIER_CACHE_TTL_MS ?? '300000', 10) || 300000,
177	    };
178	  }
179	
180	  const config: GatewayConfig = Object.freeze({
181	    apiKey,
182	    baseUrl,
183	    mode,
184	    upstreamServers,
185	    modeOverrides,
186	    shadowMode,
187	    environment,
188	    adminKey,
189	    logLevel,
190	    classifier,
191	  });
192	
193	  return config;
194	}
195	
196	function resolveLogLevel(): GatewayConfig['logLevel'] {
197	  const raw = (process.env.LAYERINFINITE_LOG_LEVEL ?? '').trim().toLowerCase();
198	  if (['debug', 'info', 'warn', 'error'].includes(raw)) {
199	    return raw as GatewayConfig['logLevel'];
200	  }
201	  // Derive from NODE_ENV
202	  if (process.env.NODE_ENV === 'production') return 'info';
203	  if (process.env.NODE_ENV === 'test') return 'error';
204	  return 'debug';
205	}
