98	
99	  // Start periodic queue processor for retrying failed outcome logs
100	  const queueSender: QueueSender = (payload: OutcomePayload) => liApi.logOutcome(payload);
101	  const queueProcessor = startQueueProcessor(queueSender, 30_000);
102	
103	  // Start periodic flush of tracker buffer (secondary durability)
104	  tracker.startFlushTimer();
105	
106	  const server = new Server(
107	    { name: SERVER_NAME, version: SERVER_VERSION },
108	    { capabilities: { tools: {}, resources: {}, prompts: {} } },
109	  );
110	
111	  const startedAt = Date.now();
112	
113	  // ── tools/list ──────────────────────────────────────────
114	
115	  server.setRequestHandler(ListToolsRequestSchema, async (request) => {
116	    try {
117	      const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
118	      const enriched = await proxy.handleListTools(taskCtx);
119	
120	      // Strip internal fields (upstreamName, annotations) per MCP spec
121	      const tools = enriched.map((t) => ({
