  let fetcher: ScoreFetcher;
  let liApi: LiApiClient;

  beforeEach(() => {
    liApi = mockLiApi();
    fetcher = new ScoreFetcher(liApi);
  });

  it('fetches scores from API', async () => {
    const scores = await fetcher.getScores('build_failed', 'cust-1', 'agent-1');
