  server.setRequestHandler(
    { method: 'resources/list' } as never,
    async () => {
      try {
        const entries = registry.getAllUpstreams();
        const healthyCount = entries.filter((e) => registry.isHealthy(e.server.name)).length;

        const resources = [
          {
            uri: 'li://

